use std::collections::HashMap;

struct Record {
    id: usize,
    data: String,
}

fn process_records(input_list: &Vec<String>) -> HashMap<usize, Vec<String>> {
    let mut results = HashMap::new();
    for line in input_list.iter() {
        if let Some(pos) = line.find(":") {
            let id_str = &line[..pos];
            let data_part = &line[pos + 1..];
            match id_str.trim().parse::<usize>() {
                Ok(id) => {
                    if let Some(record) = Some(Record { id, data: data_part.trim().to_string() }) {
                        let entry = results.entry(record.id).or_insert_with(Vec::new);
                        entry.push(format!("{}", record.data));
                    }
                },
                Err(_) => {}
            }
        }
    }
    results
}

use std::collections::HashMap;

struct VectorSearchIndex {
    data: HashMap<String, Vec<f64>>,
}

impl VectorSearchIndex {
    fn new() -> Self {
        VectorSearchIndex { data: HashMap::new() }
    }

    fn insert_vector(&mut self, key: impl ToString, vector: &[f64]) {
        self.data.insert(key.to_string(), vector.to_vec());
    }

    fn find_closest_vector(&self, query_vector: &[f64]) -> Option<String> {
        if self.data.is_empty() {
            return None;
        }

        let mut min_distance = f64::MAX;
        let mut closest_key: Option<String> = None;

        for (key, stored_vector) in &self.data {
            let distance = self.calculate_euclidean_distance(query_vector, stored_vector);
            if distance < min_distance {
                min_distance = distance;
                closest_key = Some(key.clone());
            }
        }
        closest_key
    }

    fn calculate_euclidean_distance(&self, a: &[f64], b: &[f64]) -> f64 {
        if a.len() != b.len() || a.is_empty() {
            return f64::NAN;
        }

        let sum_of_squares: f64 = a.iter().zip(b.iter()).map(|(&x, &y)| (x - y).powi(2)).sum();
        sum_of_squares.sqrt()
    }
}

fn main() {
    let mut index = VectorSearchIndex::new();
    index.insert_vector(1.to_string(), &[1.0, 1.0]);
    index.insert_vector(2.to_string(), &[5.0, 4.0]);
    index.insert_vector(3.to_string(), &[1.1, 1.05]);

    let query = &[1.05, 1.0];
    match index.find_closest_vector(query) {
        Some(key) => println!("Found closest vector key: {}", key),
        None => println!("Index is empty.")
    }
}
